var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"안녕하세요...... 시청자 여러분......","JPN":"こんにちは……視聴者の皆さん……","ENG":"Hello, everyone...","TWN":"各位觀眾朋友們……大家好……"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"오늘은 주말 컨텐츠로 일일 아르바이트를 진행하게 됐어요.","JPN":"今日は、週末の特別コンテンツとして、一日バイトをする配信を行うことになったんです。","ENG":"As a weekend special, I'll be taking on a part time job today.","TWN":"今天是以一日打工為主題的週末特輯。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그래서 요즘 유명세를 타고 있는 카페 스트레가의 일일 종업원으로 일해볼 거에요.","JPN":"というわけでして、最近バズってるというこのカフェストレガの一日従業員として働こうと思います。","ENG":"So I'll try working as a one-day staff member at Cafe Strega, which has been getting very popular these days.","TWN":"所以，我要在最近很紅的史特雷加咖啡廳，當一天的服務生。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"그럼...... 안녕하세요! 점장님!","JPN":"ええっと……おはよう…ございます……！　店長さん！","ENG":"Alright then... Hello, Ms. Manager!","TWN":"那就……妳好！店長！"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"어려울 거 없어. 주방에서 대기하다가 주문 들어오면 레시피대로 만들기만 하면 돼.","JPN":"そう緊張せずともよい。汝は厨房に控え、注文が入ればレシピ通りに作るだけでよいのだ。","ENG":"There's nothing difficult, really. Just stand by in the kitchen and follow the recipe when we get new orders.","TWN":"沒什麼難的，只要在廚房裡等訂單過來，然後照著食譜做就可以了。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LAURA_STREGA_NULL_NULL","text":{"KOREA":"간단하지? 그럼 고생하라고.","JPN":"な？　簡単であろう？　では、頑張りたまえよ。","ENG":"Easy, right? Good luck.","TWN":"很簡單吧？那就交給妳了。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"LAURA_STREGA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"네......! 맡겨만 주...... 앗......","JPN":"はい……！　お任せくださ……あっ……","ENG":"Okay! You can count on— Oh?","TWN":"好的……！交給我……啊……"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"벌써 가버리셨네요. ......괜찮겠죠?","JPN":"もう行っちゃいました。……きっと大丈夫ですよね？","ENG":"She's already gone. I hope... I'll be alright.","TWN":"這麼快就走掉了，應該沒問題吧？"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"으음...... 왠지 이 가게 레시피는...... 독특한 것 같아요.","JPN":"うーん……このお店のレシピって何だか……独特な気がします。","ENG":"Hmm... The recipe here... seems rather interesting...","TWN":"嗯……總覺得這家店的食譜……很獨特呢。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"<color=#ffd34c>맛있어지는 묘약 한 방울</color>이라는 재료가 온 메뉴에 들어가 있어요.","JPN":"<color=#ffd34c>美味しくなる妙薬を一滴</color>という材料が全部のメニューに入ってるんです。","ENG":"Here it mentions an ingredient called <color=#ffd34c>one drop of elixir of deliciousness</color> in the recipe.","TWN":"整個菜單的餐點都有一種叫做<color=#ffd34c>讓東西變美味的藥水一滴</color>的材料。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"비법소스 같은 거겠죠?! 아마......","JPN":"秘伝のソースか何かですよね！？　きっと……","ENG":"I guess it must be some kind of a secret sauce! I think...","TWN":"這是秘製醬料吧？！大概……"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"일이 끝나고 나면, 미야도 조금만 나눠달라고 해볼래요!","JPN":"お仕事が終わったら、ミヤにも少し分けてくださいってお願いしてみます！","ENG":"I should see if I can get some once I'm done with my job here!","TWN":"工作結束後，米婭也跟店長要一點好了！"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"아! 첫 주문이에요.","JPN":"あっ！　最初の注文が入りました。","ENG":"Oh! Here's my first order.","TWN":"啊！第一份訂單來了。"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"이건 그러니까......","JPN":"えっと、これは……","ENG":"Let's see...","TWN":"所以這是……"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"인페르노 돈까스......?","JPN":"インフェルノ・トンカツ……？","ENG":"Inferno pork chops?","TWN":"地獄豬排……？"},"stage":{"bg":"CAFE","slots":{"L":null,"C":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOONA_STREGA_NULL_NULL","text":{"KOREA":"안녕~ 요리 가지러 왔는데, 지금 상황이 어때?","JPN":"やっほ～。料理を取りに来たよ、今どんな感じ？","ENG":"Hi! I came to pick up the order. How's it going?","TWN":"妳好～我來拿料理了，狀況怎麼樣了？"},"stage":{"bg":"CAFE","slots":{"L":null,"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MIYA_HB_NULL_NULL","text":{"KOREA":"콜록, 콜록! 지금 막 완성했어요.","JPN":"ケホッ！　ケホッ！　たった今完成しました。","ENG":"*Cough, cough* I just finished making it.","TWN":"咳咳，咳咳！我正好完成了。"},"stage":{"bg":"CAFE","slots":{"L":{"char_id":"MIYA_HB_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"YOONA_STREGA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};